import{useIsomorphicLayoutEffect}from"../lib/useIsomorphicLayoutEffect.js";import{useStableCallback}from"./useStableCallback.js";const DEFAULT_MUTATION_OBSERVER_OPTIONS={subtree:!0,childList:!0},useMutationObserver=(t,e,s=DEFAULT_MUTATION_OBSERVER_OPTIONS)=>{const o=useStableCallback(e);useIsomorphicLayoutEffect(()=>{if(t&&t.current){const e=new MutationObserver(o);return e.observe(t.current,s),()=>e.disconnect()}},[t,o])};export{DEFAULT_MUTATION_OBSERVER_OPTIONS,useMutationObserver};